        -- 1. สร้าง Payload พรางตาด้วยการเอา &id= ไปต่อหน้าเลขเพลงตรง ๆ
        -- (และยังคงใช้ EXD_DATA เปิดหัวเหมือนเดิมเพื่อให้ระบบสคริปต์หลักของคุณทำงานได้)
        local finalPayload = EXD_DATA .. "&id=" .. id
        
        -- 2. ส่งข้อมูลไปยัง Server (ยึดตาม RemoteEvent ในรูปของคุณ)
        ReplicatedStorage:WaitForChild("RE"):WaitForChild("1NoMoto1rVehicle1s"):FireServer("PickingScooterMusicText", finalPayload)
        ReplicatedStorage:WaitForChild("RE"):WaitForChild("PlayerToolEvent"):FireServer("ToolMusicText", finalPayload)
        
        -- 3. เปลี่ยนข้อความแสดงผลบนจออัปเดตสถานะ
        currentSongLabel.Text = "Playing: " .. id
    end
end)
